const phaseMap = {
  '1H': { phase: 'FirstHalf',       eventType: 'PhaseChange', label: 'Anpfiff!',            minute: 1  },
  'HT': { phase: 'FirstHalfBreak',  eventType: 'PhaseChange', label: 'Halbzeit!',           minute: 45 },
  '2H': { phase: 'SecondHalf',      eventType: 'PhaseChange', label: 'Wiederanpfiff!',      minute: 46 },
  'FT': { phase: 'After',           eventType: 'PhaseChange', label: 'Abpfiff!',            minute: 90 },
  'ET': { phase: 'ExtraFirstHalf',  eventType: 'PhaseChange', label: 'Verlängerung!',       minute: 91 },
  'BT': { phase: 'ExtraBreak',      eventType: 'PhaseChange', label: 'Verlängerungspause!', minute: 105 },
  'P':  { phase: 'PenaltyShootout', eventType: 'PhaseChange', label: 'Elfmeterschießen!',   minute: 121 }
};

return ($input.first().json.response || []).flatMap(f => {
  const status = f.fixture.status.short;
  const base = {
    fixtureId: f.fixture.id,
    homeTeam:  f.teams.home.name,
    awayTeam:  f.teams.away.name,
    homeScore: f.goals.home ?? 0,
    awayScore: f.goals.away ?? 0
  };

  if (status === 'FT') {
    return ['1H', 'HT', '2H', 'FT'].map(s => ({
      json: { ...base, status: s, minute: phaseMap[s].minute, ...phaseMap[s] }
    }));
  }

  if (phaseMap[status]) {
    return [{ json: { ...base, status, minute: f.fixture.status.elapsed ?? phaseMap[status].minute, ...phaseMap[status] } }];
  }

  return [];
});

const postedIds = new Set(
  ($('GET: Already posted Events').first().json.items || [])
    .map(e => e.sourceId)
);

return $input.all()
  .map(item => {
    const d = item.json;
    const sourceId = `phase-${d.fixtureId}-${d.status}`;
    return { json: { ...d, sourceId } };
  })
  .filter(item => !postedIds.has(item.json.sourceId));

